// 讀 webhook query string，組 Notion 查詢 body。
// 支援：
//   ?case=YC1868705  → 只回單一物件（案件編號 equals）
//   ?status=已發布   → 依狀態篩（預設；?status=all 不篩狀態）
const q = ($('Webhook 收 feed 請求').first().json.query) || {};
const caseId = String(q.case || q.caseId || '').trim();
const status = String(q.status || '已發布').trim();

const filters = [];
if (caseId) {
  filters.push({ property: '案件編號', rich_text: { equals: caseId } });
} else if (status && status.toLowerCase() !== 'all') {
  filters.push({ property: '狀態', select: { equals: status } });
}

const body = { page_size: 100 };
if (filters.length === 1) body.filter = filters[0];
else if (filters.length > 1) body.filter = { and: filters };

return [{ json: { notionBody: body, _query: q } }];

// 把 Notion query 結果攤平成乾淨的 feed。外部系統(FB/官網/591)直接讀這支。
const resp = $input.first().json || {};
const results = resp.results || [];

const txt   = p => ((p && (p.title || p.rich_text)) || []).map(t => t.plain_text).join('');
const num   = p => (p && p.number != null) ? p.number : null;
const sel   = p => (p && p.select && p.select.name) ? p.select.name : null;
const chk   = p => !!(p && p.checkbox);
const url   = p => (p && p.url) ? p.url : null;
const files = p => ((p && p.files) || []).map(f => (f.external && f.external.url) || (f.file && f.file.url)).filter(Boolean);

const items = results.map(page => {
  const P = page.properties || {};
  return {
    id: page.id,
    案名:       txt(P['案名']),
    案件編號:   txt(P['案件編號']),
    社區名稱:   txt(P['社區名稱']),
    地址:       txt(P['地址']),
    建物類型:   sel(P['建物類型']),
    格局:       txt(P['格局']),
    樓層:       txt(P['樓層']),
    屋齡:       num(P['屋齡']),
    總價:       txt(P['總價']),
    單價:       txt(P['單價']),
    建物坪數:   num(P['建物坪數']),
    主建物坪數: num(P['主建物坪數']),
    公設坪數:   num(P['公設坪數']),
    土地坪數:   num(P['土地坪數']),
    附屬建物:   txt(P['附屬建物']),
    有無車位:   chk(P['有無車位']),
    車位類型:   sel(P['車位類型']),
    特色說明:   txt(P['特色說明']),
    粉專文案:   txt(P['粉專文案']),
    粉專貼文連結: url(P['粉專貼文連結']),
    來源連結:   url(P['來源連結']),
    狀態:       sel(P['狀態']),
    物件照片:   files(P['物件照片']),
    最後更新:   page.last_edited_time,
  };
});

return [{ json: {
  ok: true,
  generated_at: new Date().toISOString(),
  source: 'notion:07ee845168b64f8a9b5682e5069c733b',
  count: items.length,
  has_more: !!resp.has_more,
  items,
}}];
